use hyper::{Body, Request, Response, StatusCode};
use reqwest;
use std::convert::TryInto;
use tokio;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let client = reqwest::Client::new();
    
    let make_svc = hyper::service::service_fn(move |req: Request<Body>| {
        let client = client.clone();
        async move {
            handle_request(req, client).await
        }
    });

    let addr = "127.0.0.1:3000".parse().unwrap();
    let server = hyper::Server::bind(&addr).serve(make_svc);

    println!("Server running on http://{}", addr);
    server.await?;

    Ok(())
}

async fn handle_request(
    req: Request<Body>,
    client: reqwest::Client,
) -> Result<Response<Body>, hyper::Error> {
    let query = req.uri().query().unwrap_or("");
    let url = url::Url::parse(&format!("https://{}", query))
        .map_err(|_| hyper::Error::from(std::io::Error::new(std::io::ErrorKind::Other, "Invalid URL")))?;
    
    let mut request_builder = client.get(url);
    
    for (header_name, header_value) in req.headers().iter() {
        request_builder = request_builder.header(header_name.as_str(), header_value);
    }
    
    let response = request_builder.send().await
        .map_err(|_| hyper::Error::from(std::io::Error::new(std::io::ErrorKind::Other, "Request failed")))?;
    
    let status = StatusCode::from_u16(response.status().as_u16())
        .map_err(|_| hyper::Error::from(std::io::Error::new(std::io::ErrorKind::Other, "Invalid status code")))?;
    
    let body = response.bytes().await
        .map_err(|_| hyper::Error::from(std::io::Error::new(std::io::ErrorKind::Other, "Failed to read body")))?;
    
    let response = Response::builder()
        .status(status)
        .body(Body::from(body.to_vec()))
        .map_err(|_| hyper::Error::from(std::io::Error::new(std::io::ErrorKind::Other, "Failed to build response")))?;
    
    Ok(response)
}